--
-- Table structure for table `caipiao_huodong`
--

DROP TABLE IF EXISTS `caipiao_huodong`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_huodong` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'ID khuyến mãi',
  `title` varchar(255) NOT NULL COMMENT 'tiêu đề khuyến mãi',
  `desc` varchar(500) DEFAULT NULL COMMENT 'Hoạt động',
  `content` text COMMENT 'Hoạt độngnội dung(HTM L)',
  `terms` text COMMENT '',
  `banner` varchar(500) DEFAULT NULL COMMENT 'hình ảnh banner',
  `images` text COMMENT 'hình ảnh chi tiết(JSO N)',
  `type` varchar(20) DEFAULT 'other' COMMENT 'Hoạt động Loại: deposit(nạp tiền)/reward(thưởng)/other()',
  `category` varchar(50) DEFAULT 'all' COMMENT 'danh mục khuyến mãimã',
  `type_code` varchar(50) DEFAULT NULL COMMENT 'loại khuyến mãimã',
  `start_date` date DEFAULT NULL COMMENT '',
  `end_date` date DEFAULT NULL COMMENT '',
  `start_time` int(11) DEFAULT NULL COMMENT 'thời gian',
  `end_time` int(11) DEFAULT NULL COMMENT 'thời gian',
  `status` tinyint(1) DEFAULT '1' COMMENT 'Trạng thái: 1=Kích hoạt, 0=Vô hiệu hóa',
  `sort` int(11) DEFAULT '0' COMMENT 'Sắp xếp',
  `jump_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Loại: 0=chi tiết mặc định 1=điểm danh 2=UR L',
  `jump_url` varchar(500) DEFAULT '' COMMENT 'UR L',
  `required_deposit` decimal(10,2) DEFAULT '0.00' COMMENT 'điểm danhnạp tiền Số tiền',
  `required_bet` decimal(10,2) DEFAULT '0.00' COMMENT 'điểm danhđặt cược Số tiền',
  `created_at` int(11) DEFAULT NULL COMMENT 'Thời gian tạo',
  `updated_at` int(11) DEFAULT NULL COMMENT 'Thời gian cập nhật',
  PRIMARY KEY (`id`),
  KEY `idx_type` (`type`),
  KEY `idx_status` (`status`),
  KEY `idx_sort` (`sort`),
  KEY `idx_time` (`start_time`,`end_time`),
  KEY `idx_category` (`category`),
  KEY `idx_type_code` (`type_code`),
  KEY `idx_game_category_code` (`category`),
  KEY `idx_activity_type_code` (`type_code`)
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COMMENT='Hoạt độngBảng';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `caipiao_huodong`
--

LOCK TABLES `caipiao_huodong` WRITE;
/*!40000 ALTER TABLE `caipiao_huodong` DISABLE KEYS */;
INSERT INTO `caipiao_huodong` VALUES (12,'新人礼包 首存彩金','','<p>&lt;div style=\"text-align: center;\"&gt;&lt;h2 style=\"font-size: 18px; font-weight: bold; margin: 10px 0;\"&gt;新人礼包&lt;/h2&gt;&lt;/div&gt;&lt;p style=\"font-size: 14px; font-weight: bold; margin: 8px 0;\"&gt;Hoạt động对象：新注册会员&lt;/p&gt;&lt;p style=\"font-size: 14px; font-weight: bold; margin: 8px 0;\"&gt;Hoạt động时间：2024.03.24（即日起）&lt;/p&gt;&lt;p style=\"font-size: 14px; font-weight: bold; margin: 8px 0;\"&gt;Hoạt động详情：&lt;/p&gt;&lt;p&gt;&lt;img src=\"https://web.hwyla8.net/siteadmin/upload/img/1771866511772987393.avif\" style=\"max-width: 100%; display: block; margin: 10px auto;\"&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7;\"&gt;&lt;strong&gt;&lt;span style=\"color: #169179;\"&gt;例：&lt;/span&gt;新注册会员在24小时内首次存款1000USDT，即可申请18USDT新人礼包，&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7;\"&gt;&lt;strong&gt;&lt;span style=\"color: #169179;\"&gt;—倍流水&lt;/span&gt; 即可提款！&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; margin-top: 15px;\"&gt;&lt;strong&gt;申请方式：联系TG客服 &lt;a href=\"https://t.me/hwyx10\" style=\"color: #169179; text-decoration: none;\"&gt;@hwyx10&lt;/a&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px;\"&gt;&lt;strong&gt;点击Người dùng名可直接跳转咨询&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; font-weight: bold; margin: 15px 0 10px 0;\"&gt;Hoạt động规则：&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7; margin-bottom: 8px;\"&gt;&lt;strong&gt;1、符合申请条件的会员请在&lt;span style=\"color: #169179;\"&gt;注册24小时内&lt;/span&gt;申请，逾期视为自动放弃优惠；&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7; margin-bottom: 8px;\"&gt;&lt;strong&gt;2、会员需在存款后且未进行任何投注，如未申请或在申请前进行投注，则视为放弃参与该优惠；&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7; margin-bottom: 8px;\"&gt;&lt;strong&gt;3、参与首存Hoạt động，&lt;span style=\"color: #169179;\"&gt;禁止无风险投注，禁止下注电子游艺（桌面游戏，轮盘游戏等），棋牌游戏（大小，单双，百家乐，龙虎斗等50%概率的游戏）&lt;/span&gt;，否则将扣除优惠，并退还本金到游戏账户，完成一倍流水即可正常取款！&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7; margin-bottom: 8px;\"&gt;&lt;strong&gt;4、每位会员IP地址只能享有一次优惠，若会员多IP重复申请账号行为，公司保留取消或收回会员彩金的权利；&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7; margin-bottom: 8px;\"&gt;&lt;strong&gt;5、所获彩金&lt;span style=\"color: #169179;\"&gt;仅限【电子游艺】【捕鱼游戏】【棋牌游戏】一倍流水&lt;/span&gt;即可提款；&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7; margin-bottom: 8px;\"&gt;&lt;strong&gt;6、平台保留对Hoạt động的最终解释权；参与此优惠Bảng示您同意&lt;span style=\"color: #169179;\"&gt;《优惠规则与条款》&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;</p>',NULL,'/app/admin/upload/img/20261218/69441acc432c.avif','','','all','general_activity','2026-12-19','2026-02-01',1766076946,1769875200,1,880,0,'',0.00,0.00,1766070996,1766076805),(13,'电子狂欢 新周俸禄','','<p>&lt;div class=\"\"&gt;1.每周电子游艺有效投注5000或以上，将获得一定Số tiền奖金，打码越多，奖励越多，最高奖励2888；&lt;br&gt;2.满足条件即可领取，且不同Số tiền皆可逐一领取；&lt;br&gt;3.奖励仅限在iOS、Android、H5、Web手动领取；每周一领取，过期作废；&lt;br&gt;4.本Hoạt động所赠送的奖金（不含本金）需1倍流水（即稽核、打码或有效投注）才能提现，打码不限游戏平台；&lt;br&gt;5.本Hoạt động仅限账号本人进行正常的人为操作，禁止租借、使用外挂、机器人、不同账号对赌、互刷、套利、接口、协议、利用漏洞、群控或其他技术手段参与，否则将取消或扣除奖励、冻结、甚至拉入黑名单；&lt;br&gt;6.为避免文字理解差异，平台将保留本Hoạt động最终解释权。&lt;/div&gt;</p>',NULL,'/app/admin/upload/img/20261218/69441e4f1ec9.avif','','','slot','weekly_salary','2026-12-19','2026-02-01',1766074735,1769875200,1,870,0,'',0.00,0.00,1766071896,1766074595),(14,'电子狂欢 幸运注单','','<p>&lt;div class=\"\"&gt;1.会员每日在指定平台 【PG 电子】游戏单笔有效注单Số tiền大于等于1，且该笔注单尾号与Hoạt động规定尾号相同，即可获得对应有效投注（有效投注 = 下注Số tiền）额的倍数奖金，最高奖金上限2888；&lt;br&gt;2.每日领取次数3次；&lt;br&gt;3.奖励仅限在iOS、Android、H5、Web手动领取，每日过期作废（即未主动领取视为自愿放弃）；&lt;br&gt;4.本Hoạt động所赠送的奖金（不含本金）需1倍流水（即稽核、打码或有效投注）才能提现，打码不限游戏平台；&lt;br&gt;5.本Hoạt động仅限账号本人进行正常游戏投注，禁止租借账号、无风险投注(对赌、对刷、低赔刷水)、恶意套利、使用外挂程式、机器人、利用协议、漏洞、接口、群控或其他技术手段参与，一经查核属实，本平台有权终止会员登录、暂停会员使用网站、及没收奖金和不当盈利的权利，无需特别通知；&lt;br&gt;6.会员参与该Hoạt động时，本平台将默认会员同意且遵守对应条件等相关规定，为避免文字理解歧义，平台保有本Hoạt động最终解释权。&lt;/div&gt;</p>',NULL,'/app/admin/upload/img/20261219/694431d29db6.avif','','','slot','lucky_order','2026-12-19','2026-02-01',1766073600,1769875200,1,860,0,'',0.00,0.00,1766076894,1766082079),(15,'亏损救援金','','<p>&lt;div class=\"\"&gt;Hoạt động游戏：电子 棋牌 捕鱼&lt;br&gt;Hoạt động要求：按照对应比例每日总亏损（扣除优惠）达到要求标准&lt;br&gt;稽核打码：彩金5倍流水（稽核仅限于电子棋牌捕鱼）每日领取上限1888&lt;br&gt;领取方式：手动领取，过期自动派发&lt;br&gt;为避免文字理解差异，平台保留最终解释权&lt;br&gt;参与该优惠Bảng示您已同意《优惠规则与条款》&lt;/div&gt;</p>','','/app/admin/upload/img/20261219/694441f0f615.avif','','','slot,fish,chess','loss_rescue','2026-12-19','2026-02-01',1766073600,1769875200,1,850,0,'',0.00,0.00,1766081072,1766087835),(16,'电子狂欢 爆奖加赠iPhone 16 Pro Max','','<h1>&lt;div class=\"cusomize-content cusomize-content\" style=\"padding-left: 0.2rem; padding-right: 0.2rem; min-height: calc(var(--lobby__screen-height) - 0.4rem - 0.4rem - 0.9rem - 1.6rem);\"&gt;&lt;div id=\"person_temp3_5\" class=\"\" data-v-37a20f08=\"\"&gt;</h1><h1>&lt;div id=\"person_head\" class=\"\" data-v-37a20f08=\"\"&gt;</h1><h1>&lt;div class=\"person_lookcont\" data-v-37a20f08=\"\"&gt;</h1><h1>&lt;div class=\"person_looksubcont\" data-v-37a20f08=\"\"&gt;</h1><h1>&lt;p class=\"p1\" style=\"margin: 0rem; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretch: normal; font-size: 0.13rem; line-height: normal; font-family: \'Helvetica Neue\';\"&gt;&lt;strong&gt;&lt;span style=\"font-size: 0.26rem; color: #000000;\"&gt;Hoạt động对象：全体会员&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;</h1><h1>&lt;p class=\"p1\" style=\"margin: 0rem; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretch: normal; font-size: 0.13rem; line-height: normal; font-family: \'Helvetica Neue\';\"&gt;&lt;strong&gt;&lt;span style=\"font-size: 0.26rem; color: #000000;\"&gt;Hoạt động时间：2024年1月11日—2026年12月31日&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;</h1><h1>&lt;p class=\"p1\" style=\"margin: 0rem; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretch: normal; font-size: 0.13rem; line-height: normal; font-family: \'Helvetica Neue\';\"&gt;&lt;strong&gt;&lt;span style=\"font-size: 0.26rem; color: #000000;\"&gt;Hoạt động内容：投注电子游戏 PG CQ9 JDB PP&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;</h1><h1>&lt;p class=\"p1\" style=\"margin: 0rem; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretch: normal; font-size: 0.13rem; line-height: normal; font-family: \'Helvetica Neue\';\"&gt;&lt;strong&gt;&lt;span style=\"font-size: 0.26rem; color: #000000;\"&gt;FC 单注高倍爆奖即可获得对应彩金&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;</h1><h1>&lt;p&gt;&lt;img src=\"https://web.hwyla8.net/siteadmin/upload/img/1845882868003405825.avif\" onerror=\"this.onerror=null;this.src=\'https://www.hwdl5.com/siteadmin/upload/img/1845882868003405825.jpg\';\" style=\"max-width: 100%;\"&gt;&lt;/p&gt;</h1><h1>&lt;p class=\"p1\" style=\"box-sizing: inherit; color: #e3f3ff; padding: 0.03rem 0rem; margin: 0rem; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretch: normal; font-size: 0.13rem; line-height: normal; font-family: \'Helvetica Neue\';\"&gt;&lt;span style=\"color: #3366ff; font-size: 0.26rem;\"&gt;&lt;strong&gt;&lt;span style=\"color: #000000;\"&gt;-例：&lt;/span&gt;电子游戏中单注投注20 爆奖12000（12000除以20等于600倍）无爆奖视频即可申请188额外彩金，如提供完整爆彩视频则可申请288彩金，彩金无需打码&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;</h1><h1>&lt;p class=\"p1\" style=\"margin: 0rem; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretch: normal; font-size: 0.13rem; line-height: normal; font-family: \'Helvetica Neue\';\"&gt;&lt;strong&gt;&lt;span style=\"font-size: 0.26rem; color: #000000;\"&gt;购买免费游戏参与说明：游戏倍数按照购买的投注Số tiền计算。&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;</h1><h1>&lt;p class=\"p1\" style=\"margin: 0rem; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretch: normal; font-size: 0.13rem; line-height: normal; font-family: \'Helvetica Neue\';\"&gt;&lt;strong&gt;&lt;span style=\"font-size: 0.26rem; color: #3366ff;\"&gt;例如赏金大对决，投注Số tiền6，购买Số tiền450，爆分3000，则为500倍。&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;</h1><h1>&lt;p class=\"p1\" style=\"box-sizing: inherit; color: #e3f3ff; padding: 0.03rem 0rem; margin: 0rem; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretch: normal; font-size: 0.13rem; line-height: normal; font-family: \'Helvetica Neue\';\"&gt; &lt;/p&gt;</h1><h1>&lt;p class=\"p1\" style=\"box-sizing: inherit; color: #e3f3ff; padding: 0.03rem 0rem; margin: 0rem; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-stretc